codeExamples.typescript:
import axios from 'axios';

(async () => {
  const baseUrl = 'http://localhost:3011';
  const path = '/auth/connection-tokens';
  const url = `${baseUrl}${path}`;

  const response = await axios({
    method: 'post',
    headers: {
      'Authorization': 'Bearer 63adfd8bea624ffab4373f63d5c0fe28e552beaa85e13f11e52d5c6f9e26793b'
    },
    url
  });
  const data = response.data;
  console.log(data);
})();

codeExamples.javascript:
const baseUrl = 'http://localhost:3011';
const path = '/auth/pair';
const url = `${baseUrl}${path}`;

const response = await fetch(url, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
      "code": "N6Q8DJ",
      "worldId": "test-world-integration",
      "worldTitle": "Test World"
    })
});
const data = await response.json();
console.log(data);

codeExamples.typescript:
import axios from 'axios';

(async () => {
  const baseUrl = 'http://localhost:3011';
  const path = '/auth/pair';
  const url = `${baseUrl}${path}`;

  const response = await axios({
    method: 'post',
    headers: {
      'Content-Type': 'application/json'
    },
    url,
    data: {
        "code": "N6Q8DJ",
        "worldId": "test-world-integration",
        "worldTitle": "Test World"
      }
  });
  const data = response.data;
  console.log(data);
})();
